<div class="page-title-row"><div><span class="text-muted">Governance</span><h1>Estimate & Job Approvals</h1></div></div><div class="row g-4"><div class="col-lg-4"><div class="portal-card p-4"><h2>New approval rule</h2><form method="post" action="/portal/entity-approvals/rules" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input class="form-control" name="name" required></div><div class="col-6"><label class="form-label">Entity</label><select class="form-select" name="entity_type"><option value="estimate">Estimate</option><option value="job">Job</option></select></div><div class="col-6"><label class="form-label">Field</label><input class="form-control" name="trigger_field" value="total"></div><div class="col-6"><label class="form-label">Operator</label><select class="form-select" name="operator"><option value="gte">≥</option><option value="gt">&gt;</option><option value="lte">≤</option><option value="lt">&lt;</option><option value="eq">=</option><option value="always">Always</option></select></div><div class="col-6"><label class="form-label">Threshold</label><input class="form-control" type="number" step="0.01" name="threshold_value"></div><div class="col-12"><label class="form-label">Approver role</label><select class="form-select" name="required_role"><option>owner</option><option>office</option><option>crew_leader</option><option>administrator</option></select></div><div class="col-12"><label class="form-check"><input class="form-check-input" type="checkbox" name="active" checked> Active</label></div><div class="col-12"><button class="btn btn-primary">Create rule</button></div></form></div><div class="portal-card mt-4 p-3"><h3 class="h5">Active rules</h3><?php foreach($rules as $r):?><div class="border-bottom py-2"><strong><?=e($r['name'])?></strong><div class="small text-muted"><?=e($r['entity_type'].' '.$r['operator'].' '.($r['threshold_value']??''))?> · <?=e($r['required_role'])?></div></div><?php endforeach?></div></div><div class="col-lg-8"><div class="portal-card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Reference</th><th>Rule</th><th>Assigned role</th><th>Status</th><th>Requested</th><th>Decision</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['reference']??($r['entity_type'].' #'.$r['entity_id']))?></strong><div class="small text-muted"><?=e($r['entity_type'])?></div></td><td><?=e($r['rule_name']??'Manual')?></td><td><?=e($r['assigned_role'])?></td><td><?=e($r['status'])?></td><td><?=e($r['requested_at'])?></td><td><?php if($r['status']==='pending'):?><form method="post" action="/portal/entity-approvals/<?=$r['id']?>/decide" class="d-flex gap-1"><?=csrf_field()?><button name="status" value="approved" class="btn btn-sm btn-success">Approve</button><button name="status" value="rejected" class="btn btn-sm btn-outline-danger">Reject</button></form><?php else:?><?=e($r['decider']??'')?><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
